lass=row1><td style="padding-right:0px; border-right:none;"><div style="margin-top:2px;width:15px;background-color:#0f85a3;height:15px;"></div><td style="border-left:none">Φυσική<td align=right>25</tr><tr class=row2><td style="padding-right:0px; border-right:none;"><div style="margin-top:2px;width:15px;background-color:#8f1543;height:15px;"></div><td style="border-left:none">Χημεία<td align=right>25</tr><tr class=row1><td style="padding-right:0px; border-right:none;"><div style="margin-top:2px;width:15px;background-color:#1f4583;height:15px;"></div><td style="border-left:none">Μαθηματικά<td align=right>30</tr></table></div><div style="flex-grow:5;display:inline;float:left;width:128px;padding:5px;"><center><canvas  id="pchrt259" style="width:128px;letter-spacing:1px;border:1px solid;padding:8px;" width=200px height=200px class=dflt></center></canvas></div></div></center><br><br></div><script>
async function drawPieChart(arg_cnv,arg_dat,arg_colors){
try{
   var ws_cnv = document.getElementById(arg_cnv);
   var ws_context = ws_cnv.getContext("2d" );
   var ws_len = arg_dat.length;
   var ws_total = 0;
   for(var i = 0; i < ws_len; i++){
      ws_total += arg_dat[i];
   }
   var x = 100;
   var y = 100;
   var radius = 92;
   var startingPoint = 1.50;
   for(var i = 0; i < ws_len; i++){
      var percent = arg_dat[i] * 100 / ws_total;
      var endPoint = startingPoint + ( 2 / 100 * percent );
      ws_context.beginPath();
      ws_context.fillStyle = arg_colors[i];
      ws_context.moveTo( x, y );
      ws_context.arc( x, y, radius, startingPoint * Math.PI, endPoint * Math.PI );
      ws_context.fill();
      startingPoint = endPoint;
   }
}catch(err){alert(err);}
